solutions.javascript:
// Solution
function calc(a, b, operator) {
    switch (operator) {
        case '+':
            return a + b;
        case '-':
            return a - b;
        case '*':
            return a * b;
        case '/':
            return b === 0 ? 'Error: Division by zero' : a / b;
        default:
            return 'Error: Invalid operator';
    }
}

