class Solution:
    def calc(self, a, b, operator) -> int:
        if operator == '+':
            return a + b;
        elif operator == '-':
            return a - b;
        elif operator == '*':
            return a * b;
        elif operator == '/': # Add this elif statement
            if b == 0:
                return 'Error: Division by zero';
            else:
                return a // b; # Use integer division
        else:
            return 'Error: Invalid operator';

